const seen = new Set();
const duplicates = [];

for (const item of items) {
  const raw = item.json["CNPJ"];

  if (!raw) continue;

  const cnpj = String(raw).replace(/\D/g, "");

  if (seen.has(cnpj)) {
    duplicates.push(item); // é duplicado porque já apareceu antes
  } else {
    seen.add(cnpj); // primeiro registro
  }
}

return duplicates;
